#include <stdio.h>
#include <stdlib.h>
#include <cuda.h>

#define CACHE_LINE_SIZE 128
#define DRAM_SIZE (64 * 1024 * 1024)  // 64MB for DRAM
#define NUM_NODES (DRAM_SIZE / CACHE_LINE_SIZE)
#define ITERATIONS 100000
#define WARMUP 1000

__global__ void pointer_chase(uint64_t *nodes, uint64_t *start_indices, uint64_t *durations) {
    uint64_t start, end;
    uint32_t tid = blockIdx.x * blockDim.x + threadIdx.x;
    uint64_t node_ptr = start_indices[tid];

    start = clock64();
    for (int i = 0; i < ITERATIONS; i++) {
        node_ptr = nodes[node_ptr];
    }
    end = clock64();

    durations[tid] = (end - start) / ITERATIONS;
}

int main() {
    uint64_t *h_nodes = (uint64_t *)malloc(NUM_NODES * CACHE_LINE_SIZE);
    uint64_t *d_nodes;
    uint64_t *d_start_indices;
    uint64_t *d_durations;
    uint64_t *h_durations = (uint64_t *)malloc(sizeof(uint64_t));

    // Create random permutation
    for (int i = 0; i < NUM_NODES; i++) {
        *((uint64_t *)((char *)h_nodes + i * CACHE_LINE_SIZE)) = (i + 1) % NUM_NODES;
    }

    // Shuffle to defeat prefetcher
    for (int i = NUM_NODES - 1; i > 0; i--) {
        int j = rand() % (i + 1);
        uint64_t temp = *((uint64_t *)((char *)h_nodes + i * CACHE_LINE_SIZE));
        *((uint64_t *)((char *)h_nodes + i * CACHE_LINE_SIZE)) = 
            *((uint64_t *)((char *)h_nodes + j * CACHE_LINE_SIZE));
        *((uint64_t *)((char *)h_nodes + j * CACHE_LINE_SIZE)) = temp;
    }

    cudaMalloc(&d_nodes, NUM_NODES * CACHE_LINE_SIZE);
    cudaMalloc(&d_start_indices, sizeof(uint64_t));
    cudaMalloc(&d_durations, sizeof(uint64_t));

    cudaMemcpy(d_nodes, h_nodes, NUM_NODES * CACHE_LINE_SIZE, cudaMemcpyHostToDevice);

    // Start from random location
    uint64_t start_index = rand() % NUM_NODES;
    cudaMemcpy(d_start_indices, &start_index, sizeof(uint64_t), cudaMemcpyHostToDevice);

    // Warmup
    for (int i = 0; i < WARMUP; i++) {
        pointer_chase<<<1, 1>>>(d_nodes, d_start_indices, d_durations);
    }
    cudaDeviceSynchronize();

    // Actual measurement
    pointer_chase<<<1, 1>>>(d_nodes, d_start_indices, d_durations);
    cudaDeviceSynchronize();

    cudaMemcpy(h_durations, d_durations, sizeof(uint64_t), cudaMemcpyDeviceToHost);

    printf("%lu\n", h_durations[0]);

    free(h_nodes);
    free(h_durations);
    cudaFree(d_nodes);
    cudaFree(d_start_indices);
    cudaFree(d_durations);

    return 0;
}

