#include <stdio.h>
#include <algorithm>
#include <vector>

#define WARMUP_ITERATIONS 10
#define MEASURE_ITERATIONS 5
#define BLOCKS 256
#define THREADS 256
#define FMA_ITERATIONS 10000

__global__ void warmup_kernel(float *data) {
    float a = threadIdx.x;
    float b = blockIdx.x;
    float c = 0.0f;

    for (int i = 0; i < FMA_ITERATIONS * 100; i++) {
        c += a * b;
        a = b + c;
        b = c + a;
    }

    if (c == 123.456f) { // Prevent optimization
        data[0] = c;
    }
}

__global__ void measure_kernel(unsigned long long *clock_results) {
    unsigned long long start_clock = clock64();

    // Perform compute-intensive operations
    float a = threadIdx.x;
    float b = blockIdx.x;
    float c = 0.0f;

    for (int i = 0; i < FMA_ITERATIONS; i++) {
        c += a * b;
        a = b + c;
        b = c + a;
    }

    unsigned long long end_clock = clock64();

    if (threadIdx.x == 0 && blockIdx.x == 0) {
        clock_results[0] = start_clock;
        clock_results[1] = end_clock;
    }

    if (c == 123.456f) { // Prevent optimization
        clock_results[2] = (unsigned long long)c;
    }
}

int main() {
    // Warmup phase - run for at least 500ms
    float *d_dummy;
    cudaMalloc(&d_dummy, sizeof(float));

    for (int i = 0; i < WARMUP_ITERATIONS; i++) {
        warmup_kernel<<<BLOCKS, THREADS>>>(d_dummy);
        cudaDeviceSynchronize();
    }

    // Measurement phase
    unsigned long long *d_clock_results;
    cudaMalloc(&d_clock_results, 3 * sizeof(unsigned long long));

    cudaEvent_t start_event, stop_event;
    cudaEventCreate(&start_event);
    cudaEventCreate(&stop_event);

    std::vector<float> frequencies;

    for (int i = 0; i < MEASURE_ITERATIONS; i++) {
        cudaEventRecord(start_event);
        measure_kernel<<<BLOCKS, THREADS>>>(d_clock_results);
        cudaEventRecord(stop_event);
        cudaDeviceSynchronize();

        float elapsed_ms;
        cudaEventElapsedTime(&elapsed_ms, start_event, stop_event);

        unsigned long long h_clock_results[3];
        cudaMemcpy(h_clock_results, d_clock_results, 3 * sizeof(unsigned long long), cudaMemcpyDeviceToHost);

        unsigned long long clock_cycles = h_clock_results[1] - h_clock_results[0];
        float frequency_mhz = static_cast<float>(clock_cycles) / (elapsed_ms * 1000.0f);
        frequencies.push_back(frequency_mhz);
    }

    // Cleanup
    cudaFree(d_dummy);
    cudaFree(d_clock_results);
    cudaEventDestroy(start_event);
    cudaEventDestroy(stop_event);

    // Calculate and output median frequency
    std::sort(frequencies.begin(), frequencies.end());
    float median_frequency = frequencies[MEASURE_ITERATIONS / 2];

    printf("%.1f\n", median_frequency);

    return 0;
}

