    for (int i = 0; i < FMA_ITERATIONS; i++) {
        x = x * x + x;
    }

    unsigned long long end_clock = clock64();

    if (threadIdx.x == 0 && blockIdx.x == 0) {
        clock_results[0] = start_clock;
        clock_results[1] = end_clock;
        clock_results[2] = x; // Prevent optimization
    }
}

